import { workflow, node, trigger, expr } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'Set Data',
    parameters: {
      mode: 'manual',
      assignments: {
        assignments: [
          {
            id: 'test-field',
            name: 'test_field',
            value: 'Hello from Set node!',
            type: 'string'
          }
        ]
      }
    }
  }
});

export default workflow('run-button-visibility-test', 'run button visibility test')
  .add(manualTrigger)
  .to(setNode);
